// GetStore returns a node's state store.
func (ns *NetworkSim) GetStore(nodeID string) *gossip.StateStore {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	return ns.stores[nodeID]
}

// Clock returns the current simulation time.
func (ns *NetworkSim) Clock() uint64 {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	return ns.clock
}

// recordEvent appends an event, evicting the oldest half when the buffer is full.
func (ns *NetworkSim) recordEvent(e Event) {
	if len(ns.events) >= maxEventLog {
		n := copy(ns.events, ns.events[len(ns.events)/2:])
		ns.events = ns.events[:n]
	}
	ns.events = append(ns.events, e)
}

// EventLog returns all recorded events.
func (ns *NetworkSim) EventLog() []Event {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	log := make([]Event, len(ns.events))
	copy(log, ns.events)
	return log
}

// NodeCount returns the number of active nodes.
func (ns *NetworkSim) NodeCount() int {
	ns.mu.Lock()
	defer ns.mu.Unlock()
	return len(ns.nodes)
}

// SimRoundResult holds statistics from one gossip round.
type SimRoundResult struct {
	Exchanges   int
	PushedTotal int
	PulledTotal int
	Blocked     int
	Dropped     int
}

