+package sim
+
+import (
+    "fmt"
+    "testing"
+)
+
+// (a) Deletion propagates via Merkle-only when tombstone has higher version.
+func TestMerkleOnlySync_DeletePropagates_HigherVersion(t *testing.T) {
+    ns := NewNetworkSim(7)
+    ns.AddNode("n1", 1)
+    ns.AddNode("n2", 1)
+
+    // Both nodes start with a live value; n1 then deletes (higher version).
+    ns.GetStore("n2").Put("k", []byte("v"))        // v1 on n2
+    ns.GetStore("n1").Put("k", []byte("v"))        // v1 on n1
+    ns.GetStore("n1").Delete("k")                   // v2 tombstone on n1
+
+    for i := 0; i < 50; i++ {
+        ns.RunMerkleSyncRound()
+        if ns.Converged() {
+            break
+        }
+    }
+
+    if !ns.Converged() {
+        t.Fatal("expected convergence with merkle-only sync")
+    }
+    if _, ok := ns.GetStore("n2").Get("k"); ok {
+        t.Fatal("n2 should reflect deletion after merkle sync")
+    }
+}
+
+// (b) Delete-wins when tombstone and live entry share the same version.
+func TestMerkleOnlySync_DeleteWins_EqualVersion(t *testing.T) {
+    ns := NewNetworkSim(9)
+    ns.AddNode("n1", 1)
+    ns.AddNode("n2", 1)
+
+    // Arrange equal versions: both reach version 2 independently.
+    ns.GetStore("n1").Put("k", []byte("v")) // v1
+    ns.GetStore("n1").Delete("k")            // v2 tombstone
+
+    ns.GetStore("n2").Put("k", []byte("v")) // v1
+    ns.GetStore("n2").Put("k", []byte("v")) // v2 live
+
+    // Run only Merkle rounds; after sync, tombstone should win.
+    for i := 0; i < 50; i++ {
+        ns.RunMerkleSyncRound()
+        if ns.Converged() {
+            break
+        }
+    }
+
+    if !ns.Converged() {
+        t.Fatal("expected convergence with merkle-only sync")
+    }
+    if _, ok := ns.GetStore("n2").Get("k"); ok {
+        t.Fatal("delete-wins should remove live value at equal version")
+    }
+}
+
+// (c) Multi-node convergence after bulk deletes on one node using Merkle-only rounds.
+func TestMerkleOnlySync_BulkDelete_ClusterConverges(t *testing.T) {
+    ns := NewNetworkSim(42)
+    const nodes = 5
+    for i := 0; i < nodes; i++ {
+        ns.AddNode(fmt.Sprintf("n%d", i), 2)
+    }
+
+    // Prepopulate: each node writes 10 unique keys
+    for i := 0; i < nodes; i++ {
+        id := fmt.Sprintf("n%d", i)
+        for k := 0; k < 10; k++ {
+            key := fmt.Sprintf("k-%s-%02d", id, k)
+            ns.GetStore(id).Put(key, []byte("v"))
+        }
+    }
+
+    // Node n0 issues bulk deletes for half the keys in the cluster
+    // (regardless of origin). These will have high versions on n0.
+    for i := 0; i < nodes; i++ {
+        id := fmt.Sprintf("n%d", i)
+        for k := 0; k < 5; k++ { // delete 5 of the 10 per node
+            key := fmt.Sprintf("k-%s-%02d", id, k)
+            ns.GetStore("n0").Delete(key)
+        }
+    }
+
+    // Run only Merkle rounds until convergence or limit.
+    for round := 0; round < 200; round++ {
+        ns.RunMerkleSyncRound()
+        if ns.Converged() {
+            break
+        }
+    }
+    if !ns.Converged() {
+        t.Fatal("cluster did not converge with merkle-only rounds after bulk deletes")
+    }
+
+    // Verify all deleted keys are invisible on every node.
+    for i := 0; i < nodes; i++ {
+        id := fmt.Sprintf("n%d", i)
+        for k := 0; k < 5; k++ {
+            key := fmt.Sprintf("k-%s-%02d", id, k)
+            if _, ok := ns.GetStore(id).Get(key); ok {
+                t.Fatalf("node %s should not return deleted key %s", id, key)
+            }
+        }
+    }
+}
+
